package com.lamurbob28.devicedoctor;

import android.app.*;import android.app.ActivityManager.MemoryInfo;import android.content.*;import android.hardware.*;import android.net.*;import android.net.Uri;import android.os.*;import android.provider.Settings;import android.view.Gravity;import android.widget.*;
import java.io.File;import java.net.*;import java.text.*;import java.util.*;

public class DoctorActivity extends Activity{
 static final int GOOD=0,WARN=1,BAD=2,INFO=3;static final String PREFS="device_doctor_history";
 LinearLayout list;TextView netBox;Report report;String netReport="Network Doctor has not been run yet.";DecimalFormat df=new DecimalFormat("0.0");
 public void onCreate(Bundle b){super.onCreate(b);ui();scan();}
 void ui(){ScrollView sv=new ScrollView(this);sv.setFillViewport(true);sv.setBackgroundColor(0xff101114);LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(dp(18),dp(18),dp(18),dp(28));sv.addView(root);root.addView(tv("Device Doctor",30,true,0xfff1f1f1));TextView sub=tv("Smart summary, history, health score, and Network Doctor.",15,false,0xffb6bac4);sub.setPadding(0,dp(4),0,dp(14));root.addView(sub);Button r=btn("Refresh Scan");r.setOnClickListener(v->scan());root.addView(r);Button n=btn("Run Network Doctor");n.setOnClickListener(v->runNet());root.addView(n);Button c=btn("Copy Smart Report");c.setOnClickListener(v->copy());root.addView(c);Button s=btn("Share Smart Report");s.setOnClickListener(v->share());root.addView(s);list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);list.setPadding(0,dp(14),0,0);root.addView(list);setContentView(sv);} 
 void scan(){History old=load();report=make(old);list.removeAllViews();scoreCard();card("Smart Summary",report.summary);card("What Changed",report.changes);diagnosis();netCard();shortcuts();card("Full Raw Details",report.raw);save(report);} 
 Report make(History old){Report r=new Report();r.time=now();r.score=100;StringBuilder raw=new StringBuilder();String patch=safe(Build.VERSION.SECURITY_PATCH);r.patch=patch;raw.append("DEVICE\n").append(line("Manufacturer",safe(Build.MANUFACTURER))).append(line("Model",safe(Build.MODEL))).append(line("Device",safe(Build.DEVICE))).append(line("Brand",safe(Build.BRAND))).append(line("Android",safe(Build.VERSION.RELEASE))).append(line("SDK",String.valueOf(Build.VERSION.SDK_INT))).append(line("Security patch",patch)).append(line("Build ID",safe(Build.ID))).append("\n");checkPatch(r,patch);int th=thermal();r.thermal=th;raw.append("THERMAL\n").append(line("Thermal status",th>=0?thermalName(th):"Unavailable")).append("\n");checkThermal(r,th);Bat b=bat();r.temp=b.temp;raw.append("BATTERY\n").append(line("Level",b.level>=0?b.level+"%":"Unknown")).append(line("Status",batStatus(b.status))).append(line("Plugged in",plugName(b.plug))).append(line("Health",batHealth(b.health))).append(line("Temperature",b.temp>=0?df.format(b.temp)+" C":"Unknown")).append(line("Voltage",b.mv>0?b.mv+" mV":"Unknown")).append(line("Technology",b.tech)).append("\n");checkBat(r,b);Store st=store();r.used=st.used;r.usedPct=st.pct;raw.append("STORAGE\n").append(line("Internal total",bytes(st.total))).append(line("Internal used",bytes(st.used)+" ("+df.format(st.pct)+"%)")).append(line("Internal free",bytes(st.free))).append("\n");checkStore(r,st);Net nt=net();r.netValid=nt.valid;r.netType=nt.type;raw.append("NETWORK\n").append(line("Type",nt.type)).append(line("Internet capability",yn(nt.internet))).append(line("Validated internet",yn(nt.valid))).append(line("Not metered",yn(nt.unmetered))).append(line("Link downstream",nt.down>=0?nt.down+" Kbps estimate":"Unknown")).append(line("Link upstream",nt.up>=0?nt.up+" Kbps estimate":"Unknown")).append("\n");checkNet(r,nt);Mem m=mem();raw.append("MEMORY\n").append(line("System available",bytes(m.avail))).append(line("System low memory",yn(m.low))).append(line("Low memory threshold",bytes(m.threshold))).append(line("App max heap",bytes(m.max))).append(line("App used heap",bytes(m.used))).append(line("App free heap",bytes(m.free))).append("\n");checkMem(r,m);Sensors se=sensors();raw.append("SENSORS\n").append(line("Total sensors",String.valueOf(se.total)));for(String x:se.names)raw.append("- ").append(x).append("\n");if(se.more>0)raw.append("- +").append(se.more).append(" more\n");raw.append("\n");finding(r,GOOD,"Sensors",se.total+" sensors detected.","Sensor service is responding normally.",0,null,null);long up=SystemClock.uptimeMillis(),el=SystemClock.elapsedRealtime();r.uptimeDays=el/86400000L;raw.append("SYSTEM TIME\n").append(line("Uptime awake",dur(up))).append(line("Elapsed since boot",dur(el))).append(line("Automatic time",setting(Settings.Global.AUTO_TIME))).append(line("Automatic timezone",setting(Settings.Global.AUTO_TIME_ZONE))).append("\n");checkUptime(r,el);if(r.score<0)r.score=0;if(r.score>100)r.score=100;r.status=(r.score>=85&&r.bad==0)?GOOD:(r.score>=60?WARN:BAD);r.summary=summary(r);r.changes=changes(old,r);r.raw=raw.append("SUMMARY\n").append(line("Overall status",name(r.status))).append(line("Score",r.score+"/100")).append(line("Warnings",String.valueOf(r.warn))).append(line("Bad issues",String.valueOf(r.bad))).append(line("Good checks",String.valueOf(r.good))).toString();r.full=shareText(r);return r;}
 String summary(Report r){StringBuilder s=new StringBuilder();s.append("Status: ").append(name(r.status)).append("\nScore: ").append(r.score).append("/100\n").append(r.bad).append(" bad, ").append(r.warn).append(" warnings, ").append(r.good).append(" good, ").append(r.info).append(" info\nScan time: ").append(r.time).append("\n\n");if(r.bad==0&&r.warn==0)s.append("Problems found: none. The phone looks healthy from this scan.\n");else{ s.append("Problems found:\n");for(F f:r.fs)if(f.sev==BAD||f.sev==WARN)s.append("- ").append(name(f.sev)).append(": ").append(f.title).append(" - ").append(f.detail).append("\n");}s.append("\nHealthy checks:\n");int n=0;for(F f:r.fs)if(f.sev==GOOD){s.append("- ").append(f.title).append("\n");if(++n>=5)break;}return s.toString();}
 String changes(History h,Report r){if(h==null)return "No previous scan history yet. Run another scan later and Device Doctor will compare score, storage, battery temperature, network validation, and patch status.";StringBuilder s=new StringBuilder();int sd=r.score-h.score;long ud=r.used-h.used;s.append("Previous scan: ").append(h.time).append("\nCurrent scan: ").append(r.time).append("\n\n").append("Score: ").append(h.score).append(" -> ").append(r.score).append(" (").append(sign(sd)).append(")\n").append("Storage used: ").append(bytes(h.used)).append(" -> ").append(bytes(r.used)).append(" (").append(signBytes(ud)).append(")\n");if(h.temp>=0&&r.temp>=0){double td=r.temp-h.temp;s.append("Battery temp: ").append(df.format(h.temp)).append(" C -> ").append(df.format(r.temp)).append(" C (").append(td>=0?"+":"").append(df.format(td)).append(" C)\n");}else s.append("Battery temp: not enough history data\n");if(!r.patch.equals(h.patch))s.append("Security patch changed: ").append(h.patch).append(" -> ").append(r.patch).append("\n");else s.append("Security patch: unchanged (").append(r.patch).append(")\n");if(r.netValid!=h.netValid)s.append("Network validation changed: ").append(yn(h.netValid)).append(" -> ").append(yn(r.netValid)).append("\n");else s.append("Network validation: unchanged (").append(yn(r.netValid)).append(")\n");if(Math.abs(sd)<3&&Math.abs(ud)<200L*1024L*1024L)s.append("\nOverall: stable since the last scan.");else if(sd>0)s.append("\nOverall: improved since the last scan.");else if(sd<0)s.append("\nOverall: worse than the last scan. Check the warnings above.");else s.append("\nOverall: mostly unchanged.");return s.toString();}
 String shareText(Report r){return "Device Doctor v2.2 Smart Report\n\nSMART SUMMARY\n"+r.summary+"\nWHAT CHANGED\n"+r.changes+"\nRAW DETAILS\n"+r.raw+"\nNETWORK DOCTOR\n"+netReport;}
 void runNet(){if(netBox!=null)netBox.setText("Running network tests...");Toast.makeText(this,"Running Network Doctor",Toast.LENGTH_SHORT).show();new Thread(()->{String out=netTests();netReport=out;if(report!=null)report.full=shareText(report);runOnUiThread(()->{if(netBox!=null)netBox.setText(out);Toast.makeText(this,"Network Doctor finished",Toast.LENGTH_SHORT).show();});}).start();}
 String netTests(){StringBuilder s=new StringBuilder();Net n=net();s.append("Network Doctor v2.2\nRun time: ").append(now()).append("\n\n").append(line("Android network type",n.type)).append(line("Android validated",yn(n.valid))).append(line("Android internet capability",yn(n.internet))).append("\nTESTS\n");TR dg=dns("google.com"),dc=dns("cloudflare.com"),c1=tcp("1.1.1.1",443,3000),c8=tcp("8.8.8.8",443,3000);HR h=http("https://www.google.com/generate_204",5000);s.append(fmt("DNS google.com",dg)).append(fmt("DNS cloudflare.com",dc)).append(fmt("TCP 1.1.1.1:443",c1)).append(fmt("TCP 8.8.8.8:443",c8)).append("HTTPS generate_204: ").append(h.ok?"OK":"FAILED").append(" in ").append(h.ms).append(" ms (HTTP ").append(h.code).append(")");if(h.err!=null)s.append(" - ").append(h.err);s.append("\n\nRESULT\n");int p=0;if(!n.has||!n.internet)p++;if(!dg.ok&&!dc.ok)p++;if(!c1.ok&&!c8.ok)p++;if(!h.ok)p++;if(c1.ok&&c1.ms>800)p++;if(p==0)s.append("Status: GOOD\nInternet looks reachable. Latency and DNS are healthy.\n");else if(p<=2)s.append("Status: WARNING\nSome network checks failed or looked slow. Try toggling Wi-Fi, switching networks, or restarting the router if this keeps happening.\n");else s.append("Status: BAD\nMultiple network checks failed. This connection may be broken, captive, or blocked.\n");return s.toString();}
 TR dns(String host){TR r=new TR();long st=SystemClock.elapsedRealtime();try{InetAddress[] a=InetAddress.getAllByName(host);r.ms=SystemClock.elapsedRealtime()-st;r.ok=a!=null&&a.length>0;r.msg=r.ok?a[0].getHostAddress():"No addresses";}catch(Exception e){r.ms=SystemClock.elapsedRealtime()-st;r.msg=err(e);}return r;}
 TR tcp(String host,int port,int to){TR r=new TR();long st=SystemClock.elapsedRealtime();Socket so=new Socket();try{so.connect(new InetSocketAddress(host,port),to);r.ok=true;r.msg="Connected";}catch(Exception e){r.msg=err(e);}finally{r.ms=SystemClock.elapsedRealtime()-st;try{so.close();}catch(Exception ignored){}}return r;}
 HR http(String u,int to){HR r=new HR();long st=SystemClock.elapsedRealtime();HttpURLConnection c=null;try{c=(HttpURLConnection)new URL(u).openConnection();c.setConnectTimeout(to);c.setReadTimeout(to);c.setUseCaches(false);c.setInstanceFollowRedirects(false);c.connect();r.code=c.getResponseCode();r.ok=r.code>=200&&r.code<400;}catch(Exception e){r.code=-1;r.err=err(e);}finally{r.ms=SystemClock.elapsedRealtime()-st;if(c!=null)c.disconnect();}return r;}
 String fmt(String label,TR r){return label+": "+(r.ok?"OK":"FAILED")+" in "+r.ms+" ms - "+r.msg+"\n";}
 void checkBat(Report r,Bat b){if(b.temp<0)finding(r,INFO,"Battery Temperature","Temperature is unavailable.","Android did not expose battery temperature on this scan.",0,null,null);else if(b.temp>=45)finding(r,BAD,"Battery Temperature","Battery is very hot: "+df.format(b.temp)+" C.","Stop heavy use and let the phone cool down.",20,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");else if(b.temp>=40)finding(r,BAD,"Battery Temperature","Battery is hot: "+df.format(b.temp)+" C.","Heat wears batteries down faster.",15,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");else if(b.temp>=35)finding(r,WARN,"Battery Temperature","Battery is warm: "+df.format(b.temp)+" C.","Avoid stacking heat with gaming plus charging.",5,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");else finding(r,GOOD,"Battery Temperature","Battery temperature looks normal: "+df.format(b.temp)+" C.","No heat problem detected.",0,null,null);if(b.health==BatteryManager.BATTERY_HEALTH_GOOD)finding(r,GOOD,"Battery Health","Android reports battery health as good.","Nothing concerning detected here.",0,null,null);else if(b.health<=0||b.health==BatteryManager.BATTERY_HEALTH_UNKNOWN)finding(r,INFO,"Battery Health","Battery health is unknown.","Some devices do not expose useful battery health data.",0,null,null);else finding(r,BAD,"Battery Health","Android reports battery health as "+batHealth(b.health)+".","Watch charging, heat, and sudden shutdowns.",20,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");}
 void checkStore(Report r,Store s){if(s.pct>=95)finding(r,BAD,"Storage","Storage is critically full: "+df.format(s.pct)+"% used.","Free space soon.",30,"Open Storage Settings","android.settings.INTERNAL_STORAGE_SETTINGS");else if(s.pct>=90)finding(r,BAD,"Storage","Storage is very full: "+df.format(s.pct)+"% used.","Clear downloads, videos, cache, or unused apps.",20,"Open Storage Settings","android.settings.INTERNAL_STORAGE_SETTINGS");else if(s.pct>=80)finding(r,WARN,"Storage","Storage is getting high: "+df.format(s.pct)+"% used.","Cleanup is not urgent, but it is getting close.",10,"Open Storage Settings","android.settings.INTERNAL_STORAGE_SETTINGS");else finding(r,GOOD,"Storage","Storage looks okay: "+df.format(s.pct)+"% used.","Free space is not currently a problem.",0,null,null);}
 void checkNet(Report r,Net n){if(!n.has)finding(r,BAD,"Network","No active network detected.","Connect to Wi-Fi or mobile data.",20,"Open Wi-Fi Settings","android.settings.WIFI_SETTINGS");else if(!n.internet)finding(r,BAD,"Network","A network exists, but Android does not see internet capability.","Reconnect or switch networks.",20,"Open Wi-Fi Settings","android.settings.WIFI_SETTINGS");else if(!n.valid)finding(r,WARN,"Network","Connected, but Android has not validated real internet.","Run Network Doctor or check for a login page.",10,"Open Wi-Fi Settings","android.settings.WIFI_SETTINGS");else finding(r,GOOD,"Network","Internet connection is validated on "+n.type+".","Network looks normal from Android's view.",0,null,null);if(n.has&&!n.unmetered)finding(r,INFO,"Metered Network","This connection may be metered.","Large downloads may use mobile data or a limited connection.",0,"Open Network Settings","android.settings.WIRELESS_SETTINGS");}
 void checkMem(Report r,Mem m){if(m.low)finding(r,WARN,"Memory","Android reports low memory pressure.","Close heavy apps or restart if sluggish.",10,"Open App Settings","APP_DETAILS");else finding(r,GOOD,"Memory","Android is not reporting low memory pressure.","No RAM emergency detected.",0,null,null);}
 void checkThermal(Report r,int t){if(t<0)finding(r,INFO,"Thermals","Thermal status is unavailable.","This Android version may not expose it.",0,null,null);else if(t==PowerManager.THERMAL_STATUS_NONE)finding(r,GOOD,"Thermals","System thermal status is normal.","No thermal throttling reported.",0,null,null);else if(t==PowerManager.THERMAL_STATUS_LIGHT)finding(r,WARN,"Thermals","System thermal status is light.","The phone is slightly warm.",5,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");else if(t==PowerManager.THERMAL_STATUS_MODERATE)finding(r,WARN,"Thermals","System thermal status is moderate.","Let the phone cool if performance feels worse.",10,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");else finding(r,BAD,"Thermals","System thermal status is "+thermalName(t)+".","Stop heavy use and let the phone cool down.",25,"Open Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");}
 void checkPatch(Report r,String p){long d=patchAge(p);r.patchDays=d;if(d<0)finding(r,INFO,"Security Patch","Security patch date is unavailable.","Check Android updates manually.",0,"Open System Update","android.settings.SYSTEM_UPDATE_SETTINGS");else if(d<=90)finding(r,GOOD,"Security Patch","Security patch is recent: "+p+".","Patch age is about "+d+" days.",0,null,null);else if(d<=180)finding(r,WARN,"Security Patch","Security patch is aging: "+p+".","Patch age is about "+d+" days. Check for updates.",5,"Open System Update","android.settings.SYSTEM_UPDATE_SETTINGS");else if(d<=365)finding(r,WARN,"Security Patch","Security patch is stale: "+p+".","Patch age is about "+d+" days. System update check recommended.",10,"Open System Update","android.settings.SYSTEM_UPDATE_SETTINGS");else finding(r,BAD,"Security Patch","Security patch is very old: "+p+".","Patch age is about "+d+" days. Update if possible.",20,"Open System Update","android.settings.SYSTEM_UPDATE_SETTINGS");}
 void checkUptime(Report r,long e){long d=e/86400000L;if(d>=30)finding(r,WARN,"Uptime","Phone has been running for "+d+" days since boot.","Restarting can clear background-service problems.",15,"Open Device Settings","android.settings.SETTINGS");else if(d>=14)finding(r,WARN,"Uptime","Phone has been running for "+d+" days since boot.","A restart may help if anything feels strange.",10,"Open Device Settings","android.settings.SETTINGS");else if(d>=7)finding(r,WARN,"Uptime","Phone has been running for "+d+" days since boot.","A restart can freshen things up.",5,"Open Device Settings","android.settings.SETTINGS");else finding(r,GOOD,"Uptime","Recent boot: "+dur(e)+" since startup.","No restart recommendation right now.",0,null,null);}
 void finding(Report r,int sev,String title,String detail,String advice,int penalty,String label,String action){F f=new F();f.sev=sev;f.title=title;f.detail=detail;f.advice=advice;f.label=label;f.action=action;r.fs.add(f);r.score-=penalty;if(sev==BAD)r.bad++;else if(sev==WARN)r.warn++;else if(sev==GOOD)r.good++;else r.info++;}
 Bat bat(){Bat o=new Bat();Intent b=registerReceiver(null,new IntentFilter(Intent.ACTION_BATTERY_CHANGED));if(b==null)return o;int l=b.getIntExtra(BatteryManager.EXTRA_LEVEL,-1),sc=b.getIntExtra(BatteryManager.EXTRA_SCALE,-1);o.level=(l>=0&&sc>0)?Math.round(l*100f/sc):-1;o.status=b.getIntExtra(BatteryManager.EXTRA_STATUS,-1);o.plug=b.getIntExtra(BatteryManager.EXTRA_PLUGGED,-1);o.health=b.getIntExtra(BatteryManager.EXTRA_HEALTH,-1);int t=b.getIntExtra(BatteryManager.EXTRA_TEMPERATURE,-1);o.temp=t>=0?t/10.0:-1;o.mv=b.getIntExtra(BatteryManager.EXTRA_VOLTAGE,-1);String tech=b.getStringExtra(BatteryManager.EXTRA_TECHNOLOGY);o.tech=tech==null?"Unknown":tech;return o;}
 Store store(){Store o=new Store();File p=Environment.getDataDirectory();StatFs st=new StatFs(p.getPath());long bs=st.getBlockSizeLong();o.total=st.getBlockCountLong()*bs;o.free=st.getAvailableBlocksLong()*bs;o.used=o.total-o.free;o.pct=o.total>0?o.used*100.0/o.total:0;return o;}
 Net net(){Net o=new Net();o.type="None";o.down=-1;o.up=-1;ConnectivityManager cm=(ConnectivityManager)getSystemService(CONNECTIVITY_SERVICE);if(cm==null)return o;Network nw=cm.getActiveNetwork();if(nw==null)return o;o.has=true;NetworkCapabilities c=cm.getNetworkCapabilities(nw);if(c==null)return o;if(c.hasTransport(NetworkCapabilities.TRANSPORT_WIFI))o.type="Wi-Fi";else if(c.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR))o.type="Cellular";else if(c.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET))o.type="Ethernet";else if(c.hasTransport(NetworkCapabilities.TRANSPORT_VPN))o.type="VPN";else o.type="Other";o.internet=c.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET);o.valid=c.hasCapability(NetworkCapabilities.NET_CAPABILITY_VALIDATED);o.unmetered=c.hasCapability(NetworkCapabilities.NET_CAPABILITY_NOT_METERED);o.down=c.getLinkDownstreamBandwidthKbps();o.up=c.getLinkUpstreamBandwidthKbps();return o;}
 Mem mem(){Mem o=new Mem();ActivityManager am=(ActivityManager)getSystemService(ACTIVITY_SERVICE);MemoryInfo i=new MemoryInfo();if(am!=null){am.getMemoryInfo(i);o.avail=i.availMem;o.low=i.lowMemory;o.threshold=i.threshold;}Runtime rt=Runtime.getRuntime();o.max=rt.maxMemory();long total=rt.totalMemory(),free=rt.freeMemory();o.used=total-free;o.free=free;return o;}
 Sensors sensors(){Sensors o=new Sensors();SensorManager sm=(SensorManager)getSystemService(SENSOR_SERVICE);if(sm==null)return o;List<Sensor> ss=sm.getSensorList(Sensor.TYPE_ALL);o.total=ss.size();int lim=Math.min(8,ss.size());for(int i=0;i<lim;i++)o.names.add(ss.get(i).getName());o.more=ss.size()-lim;return o;}
 int thermal(){if(Build.VERSION.SDK_INT<29)return -1;try{return ((PowerManager)getSystemService(POWER_SERVICE)).getCurrentThermalStatus();}catch(Exception e){return -1;}}
 History load(){SharedPreferences p=getSharedPreferences(PREFS,MODE_PRIVATE);if(!p.contains("time"))return null;History h=new History();h.time=p.getString("time","Unknown");h.score=p.getInt("score",0);h.used=p.getLong("used",0);h.temp=Double.longBitsToDouble(p.getLong("temp",Double.doubleToLongBits(-1)));h.patch=p.getString("patch","Unknown");h.netValid=p.getBoolean("netValid",false);return h;}
 void save(Report r){getSharedPreferences(PREFS,MODE_PRIVATE).edit().putString("time",r.time).putInt("score",r.score).putLong("used",r.used).putLong("temp",Double.doubleToRawLongBits(r.temp)).putString("patch",r.patch).putBoolean("netValid",r.netValid).apply();}
 void scoreCard(){LinearLayout c=box();c.addView(tv("Overall Health",20,true,0xfff1f1f1));TextView s=tv(report.score+"/100  -  "+name(report.status),32,true,color(report.status));s.setPadding(0,dp(6),0,dp(6));c.addView(s);c.addView(tv(report.bad+" bad, "+report.warn+" warnings, "+report.good+" good, "+report.info+" info\nLast scan: "+report.time,14,false,0xffb6bac4));list.addView(c);}
 void diagnosis(){TextView h=tv("Diagnosis",22,true,0xfff1f1f1);h.setPadding(0,dp(4),0,dp(8));list.addView(h);boolean any=false;for(F f:report.fs)if(f.sev==BAD||f.sev==WARN){fcard(f);any=true;}if(!any)card("No major problems found","Nothing bad or warning-level showed up in this scan.");TextView g=tv("Other Checks",20,true,0xfff1f1f1);g.setPadding(0,dp(6),0,dp(8));list.addView(g);for(F f:report.fs)if(f.sev==GOOD||f.sev==INFO)fcard(f);}
 void fcard(F f){LinearLayout c=box();c.addView(tv(f.title+"  -  "+name(f.sev),18,true,color(f.sev)));TextView d=tv(f.detail,14,false,0xfff1f1f1);d.setPadding(0,dp(7),0,dp(3));c.addView(d);c.addView(tv(f.advice,14,false,0xffb6bac4));if(f.action!=null&&f.label!=null){Button b=btn(f.label);b.setOnClickListener(v->open(f.action));c.addView(b);}list.addView(c);}
 void netCard(){LinearLayout c=box();c.addView(tv("Network Doctor",20,true,0xfff1f1f1));netBox=tv(netReport,14,false,0xffb6bac4);netBox.setPadding(0,dp(6),0,dp(8));c.addView(netBox);Button b=btn("Run Network Doctor");b.setOnClickListener(v->runNet());c.addView(b);list.addView(c);}
 void shortcuts(){LinearLayout c=box();c.addView(tv("Useful Shortcuts",20,true,0xfff1f1f1));TextView h=tv("These open Android settings. The app does not delete anything by itself.",14,false,0xffb6bac4);h.setPadding(0,dp(4),0,dp(8));c.addView(h);addShortcut(c,"Storage Settings","android.settings.INTERNAL_STORAGE_SETTINGS");addShortcut(c,"Battery Settings","android.settings.BATTERY_SAVER_SETTINGS");addShortcut(c,"Wi-Fi Settings","android.settings.WIFI_SETTINGS");addShortcut(c,"System Update","android.settings.SYSTEM_UPDATE_SETTINGS");addShortcut(c,"This App Info","APP_DETAILS");list.addView(c);}
 void addShortcut(LinearLayout c,String label,String action){Button b=btn(label);b.setOnClickListener(v->open(action));c.addView(b);} 
 LinearLayout box(){LinearLayout c=new LinearLayout(this);c.setOrientation(LinearLayout.VERTICAL);c.setPadding(dp(14),dp(12),dp(14),dp(12));c.setBackgroundColor(0xff1b1d22);LinearLayout.LayoutParams p=new LinearLayout.LayoutParams(-1,-2);p.setMargins(0,0,0,dp(12));c.setLayoutParams(p);return c;}
 void card(String head,String body){LinearLayout c=box();TextView h=tv(head,19,true,0xfff1f1f1);h.setPadding(0,0,0,dp(7));c.addView(h);TextView b=tv(body.trim(),14,false,0xffb6bac4);b.setLineSpacing(0,1.08f);c.addView(b);list.addView(c);}Button btn(String label){Button b=new Button(this);b.setText(label);b.setAllCaps(false);return b;}void copy(){ClipboardManager c=(ClipboardManager)getSystemService(CLIPBOARD_SERVICE);if(c!=null){c.setPrimaryClip(ClipData.newPlainText("Device Doctor Report",combined()));Toast.makeText(this,"Report copied",Toast.LENGTH_SHORT).show();}}void share(){Intent s=new Intent(Intent.ACTION_SEND);s.setType("text/plain");s.putExtra(Intent.EXTRA_SUBJECT,"Device Doctor Report");s.putExtra(Intent.EXTRA_TEXT,combined());startActivity(Intent.createChooser(s,"Share Device Doctor Report"));}String combined(){if(report==null)report=make(load());return report.full;}void open(String a){try{Intent i;if("APP_DETAILS".equals(a)){i=new Intent("android.settings.APPLICATION_DETAILS_SETTINGS");i.setData(Uri.parse("package:"+getPackageName()));}else i=new Intent(a);startActivity(i);}catch(Exception e){try{startActivity(new Intent(Settings.ACTION_SETTINGS));}catch(Exception ignored){Toast.makeText(this,"Could not open settings",Toast.LENGTH_SHORT).show();}}}
 TextView tv(String v,int sp,boolean bold,int col){TextView t=new TextView(this);t.setText(v);t.setTextSize(sp);t.setTextColor(col);t.setGravity(Gravity.START);if(bold)t.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);return t;}int color(int s){return s==GOOD?0xff75d69c:s==WARN?0xffffd166:s==BAD?0xffff6b6b:0xff8ab4f8;}String name(int s){return s==GOOD?"GOOD":s==WARN?"WARNING":s==BAD?"BAD":"INFO";}String line(String l,String v){return l+": "+v+"\n";}String yn(boolean b){return b?"Yes":"No";}String safe(String v){return v==null||v.trim().length()==0?"Unknown":v;}String now(){return new SimpleDateFormat("yyyy-MM-dd HH:mm:ss",Locale.US).format(new Date());}String err(Exception e){return e.getClass().getSimpleName()+(e.getMessage()!=null?": "+e.getMessage():"");}String sign(int v){return v>=0?"+"+v:String.valueOf(v);}String signBytes(long v){return v>=0?"+"+bytes(v):"-"+bytes(Math.abs(v));}String bytes(long v){double gb=v/1024.0/1024.0/1024.0;if(gb>=1)return df.format(gb)+" GB";return df.format(v/1024.0/1024.0)+" MB";}String dur(long ms){long sec=ms/1000,d=sec/86400,h=(sec%86400)/3600,m=(sec%3600)/60;return String.format(Locale.US,"%dd %dh %dm",d,h,m);}String setting(String k){try{return Settings.Global.getInt(getContentResolver(),k)==1?"Enabled":"Disabled";}catch(Exception e){return "Unknown";}}long patchAge(String p){try{if(p==null||p.length()<10||"Unknown".equals(p))return -1;SimpleDateFormat f=new SimpleDateFormat("yyyy-MM-dd",Locale.US);f.setLenient(false);Date d=f.parse(p);if(d==null)return -1;long diff=System.currentTimeMillis()-d.getTime();return diff<0?0:diff/86400000L;}catch(Exception e){return -1;}}
 String batStatus(int s){switch(s){case BatteryManager.BATTERY_STATUS_CHARGING:return"Charging";case BatteryManager.BATTERY_STATUS_DISCHARGING:return"Discharging";case BatteryManager.BATTERY_STATUS_FULL:return"Full";case BatteryManager.BATTERY_STATUS_NOT_CHARGING:return"Not charging";default:return"Unknown";}}String plugName(int p){switch(p){case BatteryManager.BATTERY_PLUGGED_AC:return"AC charger";case BatteryManager.BATTERY_PLUGGED_USB:return"USB";case BatteryManager.BATTERY_PLUGGED_WIRELESS:return"Wireless";default:return"No";}}String batHealth(int h){switch(h){case BatteryManager.BATTERY_HEALTH_GOOD:return"Good";case BatteryManager.BATTERY_HEALTH_OVERHEAT:return"Overheat";case BatteryManager.BATTERY_HEALTH_DEAD:return"Dead";case BatteryManager.BATTERY_HEALTH_OVER_VOLTAGE:return"Over voltage";case BatteryManager.BATTERY_HEALTH_UNSPECIFIED_FAILURE:return"Failure";case BatteryManager.BATTERY_HEALTH_COLD:return"Cold";default:return"Unknown";}}String thermalName(int t){switch(t){case PowerManager.THERMAL_STATUS_NONE:return"None";case PowerManager.THERMAL_STATUS_LIGHT:return"Light";case PowerManager.THERMAL_STATUS_MODERATE:return"Moderate";case PowerManager.THERMAL_STATUS_SEVERE:return"Severe";case PowerManager.THERMAL_STATUS_CRITICAL:return"Critical";case PowerManager.THERMAL_STATUS_EMERGENCY:return"Emergency";case PowerManager.THERMAL_STATUS_SHUTDOWN:return"Shutdown";default:return"Unknown";}}int dp(int v){return Math.round(v*getResources().getDisplayMetrics().density);} 
 static class Report{int score,status,bad,warn,good,info,thermal;String time,summary,changes,raw,full,patch="Unknown",netType="Unknown";long used,uptimeDays,patchDays;double usedPct,temp=-1;boolean netValid;ArrayList<F>fs=new ArrayList<>();}static class History{String time,patch;int score;long used;double temp;boolean netValid;}static class F{int sev;String title,detail,advice,label,action;}static class Bat{int level=-1,status=-1,plug=-1,health=-1,mv=-1;double temp=-1;String tech="Unknown";}static class Store{long total,used,free;double pct;}static class Net{boolean has,internet,valid,unmetered;String type;int down,up;}static class Mem{long avail,threshold,max,used,free;boolean low;}static class Sensors{int total,more;ArrayList<String>names=new ArrayList<>();}static class TR{boolean ok;long ms;String msg;}static class HR{boolean ok;long ms;int code;String err;}
}
